{
  "children": [
    {
      "name": "RegisterPatient",
      "purpose": "Register a new patient with provided details",
      "behavior": "Validate input, check for duplicate, store patient in patients store, return success or error",
      "boundary": {
        "in_scope": ["patient registration", "duplicate check"],
        "out_of_scope": ["appointment booking", "record retrieval", "profile update"]
      },
      "semantic_inputs": [
        {"name": "input", "description": "JSON with patient details", "source": "parent input"}
      ],
      "semantic_outputs": [
        {"name": "output", "description": "JSON with success, data, message", "consumer": "parent"}
      ],
      "preconditions": ["input contains valid patient data"],
      "postconditions": ["patient is stored in patients store"],
      "guarantees": ["no duplicate patient created"],
      "composition_role": "mutate",
      "stop_decompose": false,
      "stop_reason": ""
    },
    {
      "name": "BookAppointment",
      "purpose": "Book an appointment for a registered patient",
      "behavior": "Validate patient exists, check slot availability, store appointment in appointments store, return success or error",
      "boundary": {
        "in_scope": ["appointment booking", "patient existence check", "slot availability"],
        "out_of_scope": ["registration", "records", "profile update"]
      },
      "semantic_inputs": [
        {"name": "input", "description": "JSON with patient ID and appointment details", "source": "parent input"}
      ],
      "semantic_outputs": [
        {"name": "output", "description": "JSON with success, data, message", "consumer": "parent"}
      ],
      "preconditions": ["patient is registered"],
      "postconditions": ["appointment is stored in appointments store"],
      "guarantees": ["no double booking"],
      "composition_role": "mutate",
      "stop_decompose": false,
      "stop_reason": ""
    },
    {
      "name": "GetRecords",
      "purpose": "Retrieve medical records for a patient",
      "behavior": "Validate patient exists, fetch records from patients store (append-only), return records",
      "boundary": {
        "in_scope": ["record retrieval", "patient existence"],
        "out_of_scope": ["registration", "appointment booking", "profile update"]
      },
      "semantic_inputs": [
        {"name": "input", "description": "JSON with patient ID", "source": "parent input"}
      ],
      "semantic_outputs": [
        {"name": "output", "description": "JSON with success, data (records), message", "consumer": "parent"}
      ],
      "preconditions": ["patient is registered"],
      "postconditions": ["records are returned without modification"],
      "guarantees": ["records are append-only, no modification"],
      "composition_role": "query",
      "stop_decompose": false,
      "stop_reason": ""
    },
    {
      "name": "UpdateProfile",
      "purpose": "Update patient profile information",
      "behavior": "Validate patient exists, update patient details in patients store, return success or error",
      "boundary": {
        "in_scope": ["profile update", "patient existence"],
        "out_of_scope": ["registration", "appointment booking", "records"]
      },
      "semantic_inputs": [
        {"name": "input", "description": "JSON with patient ID and updated fields", "source": "parent input"}
      ],
      "semantic_outputs": [
        {"name": "output", "description": "JSON with success, data, message", "consumer": "parent"}
      ],
      "preconditions": ["patient is registered"],
      "postconditions": ["patient profile is updated"],
      "guarantees": ["only provided fields are updated"],
      "composition_role": "mutate",
      "stop_decompose": false,
      "stop_reason": ""
    }
  ],
  "decomposition_rationale": "Each functional requirement maps to a child function that handles one operation. The parent routes based on command.",
  "orchestration_model": "conditional",
  "dataflow_sketch": [
    {"from": "parent", "to": "RegisterPatient", "data": "input", "note": "when command is register"},
    {"from": "parent", "to": "BookAppointment", "data": "input", "note": "when command is book"},
    {"from": "parent", "to": "GetRecords", "data": "input", "note": "when command is records"},
    {"from": "parent", "to": "UpdateProfile", "data": "input", "note": "when command is update"},
    {"from": "RegisterPatient", "to": "parent", "data": "output", "note": "return result"},
    {"from": "BookAppointment", "to": "parent", "data": "output", "note": "return result"},
    {"from": "GetRecords", "to": "parent", "data": "output", "note": "return result"},
    {"from": "UpdateProfile", "to": "parent", "data": "output", "note": "return result"}
  ]
}
